std::string base64(const uint8_t *data, size_t length) {
  static constexpr char alphabet[] = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  std::string encoded;
  encoded.reserve(((length + 2) / 3) * 4);
  for (size_t i = 0; i < length; i += 3) {
    const uint32_t octetA = data[i];
    const uint32_t octetB = (i + 1 < length) ? data[i + 1] : 0;
    const uint32_t octetC = (i + 2 < length) ? data[i + 2] : 0;
    const uint32_t triple = (octetA << 16) | (octetB << 8) | octetC;
    encoded.push_back(alphabet[(triple >> 18) & 0x3F]);
    encoded.push_back(alphabet[(triple >> 12) & 0x3F]);
    encoded.push_back((i + 1 < length) ? alphabet[(triple >> 6) & 0x3F] : '=');
    encoded.push_back((i + 2 < length) ? alphabet[triple & 0x3F] : '=');
  }
  return encoded;
}

std::string websocketAccept(const std::string &key) {
  const std::string magic = key + "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";
  const std::array<uint8_t, SHA1_DIGEST_BYTES> digest = sha1(magic);
  return base64(digest.data(), digest.size());
}

std::string lower(std::string value) {
  std::transform(value.begin(), value.end(), value.begin(), [](unsigned char c) { return static_cast<char>(std::tolower(c)); });
  return value;
}

std::string trim(const std::string &value) {
  const size_t first = value.find_first_not_of(" \t\r\n");
  if (first == std::string::npos) return "";
  const size_t last = value.find_last_not_of(" \t\r\n");
  return value.substr(first, last - first + 1);
}

bool sendAll(int fd, const char *data, size_t length) {
  size_t sent = 0;
  while (sent < length) {
#ifdef MSG_NOSIGNAL
    const ssize_t result = send(fd, data + sent, length - sent, MSG_NOSIGNAL);
#else
    const ssize_t result = send(fd, data + sent, length - sent, 0);
#endif
    if (result <= 0) return false;
    sent += static_cast<size_t>(result);
  }
  return true;
}

bool sendAll(int fd, const std::string &data) {
  return sendAll(fd, data.data(), data.size());
}

std::string contentTypeFor(const std::filesystem::path &path) {
  const std::string extension = lower(path.extension().string());
  if (extension == ".htm" || extension == ".html") return "text/html; charset=utf-8";
  if (extension == ".js") return "application/javascript; charset=utf-8";
  if (extension == ".css") return "text/css; charset=utf-8";
  if (extension == ".json") return "application/json; charset=utf-8";
  if (extension == ".ico") return "image/x-icon";
  if (extension == ".png") return "image/png";
  if (extension == ".gif") return "image/gif";
  return "application/octet-stream";
}

std::string httpStatusText(int status) {
  switch (status) {
    case 101: return "Switching Protocols";
    case 200: return "OK";
    case 400: return "Bad Request";
    case 404: return "Not Found";
    case 405: return "Method Not Allowed";
    case 410: return "Gone";
    case 500: return "Internal Server Error";
    case 501: return "Not Implemented";
    default: return "OK";
  }
}

bool sendHttp(int fd, int status, const std::string &contentType, const std::string &body) {
  std::ostringstream response;
  response << "HTTP/1.1 " << status << " " << httpStatusText(status) << "\r\n"
           << "Content-Type: " << contentType << "\r\n"
           << "Content-Length: " << body.size() << "\r\n"
           << "Access-Control-Allow-Origin: *\r\n"
           << "Access-Control-Allow-Methods: *\r\n"
           << "Access-Control-Allow-Headers: *\r\n"
           << "Connection: close\r\n\r\n"
           << body;
  return sendAll(fd, response.str());
}

bool parseRequest(const std::string &raw, HttpRequest &request) {
  const size_t headerEnd = raw.find("\r\n\r\n");
  if (headerEnd == std::string::npos) return false;

  std::istringstream stream(raw.substr(0, headerEnd));
  std::string requestLine;
  if (!std::getline(stream, requestLine)) return false;
  requestLine = trim(requestLine);

  std::istringstream requestLineStream(requestLine);
  if (!(requestLineStream >> request.method >> request.path)) return false;
  const size_t query = request.path.find('?');
  if (query != std::string::npos) request.path.erase(query);

  std::string line;
  while (std::getline(stream, line)) {
    const size_t separator = line.find(':');
    if (separator == std::string::npos) continue;
    request.headers[lower(trim(line.substr(0, separator)))] = trim(line.substr(separator + 1));
  }

  request.body = raw.substr(headerEnd + 4);
  return true;
}

size_t contentLengthFrom(const HttpRequest &request) {
  const auto it = request.headers.find("content-length");
  if (it == request.headers.end()) return 0;
  return static_cast<size_t>(std::strtoull(it->second.c_str(), nullptr, 10));
}

std::string readRequest(int fd) {
  std::string raw;
  char buffer[2048];
  size_t headerEnd = std::string::npos;
  size_t expectedLength = 0;

  while (raw.size() < MAX_HTTP_REQUEST_BYTES) {
    const ssize_t received = recv(fd, buffer, sizeof(buffer), 0);
    if (received <= 0) break;
    raw.append(buffer, static_cast<size_t>(received));

    if (headerEnd == std::string::npos) {
      headerEnd = raw.find("\r\n\r\n");
      if (headerEnd != std::string::npos) {
        HttpRequest parsed;
        if (parseRequest(raw, parsed)) expectedLength = headerEnd + 4 + contentLengthFrom(parsed);
      }
    }
    if (headerEnd != std::string::npos && raw.size() >= expectedLength) break;
  }
  return raw;
}

std::filesystem::path routeToAsset(const std::filesystem::path &webRoot, const std::string &path) {
  std::string asset = path;
  if (asset == "/") asset = "/index.htm";
  else if (asset == "/settings") asset = "/settings.htm";
  else if (asset == "/settings/wifi") asset = "/settings_wifi.htm";
  else if (asset == "/settings/leds") asset = "/settings_leds.htm";
  else if (asset == "/settings/pins") asset = "/settings_pininfo.htm";
  else if (asset == "/settings/2D") asset = "/settings_2D.htm";
  else if (asset == "/settings/ui") asset = "/settings_ui.htm";
  else if (asset == "/settings/dmx") asset = "/settings_dmx.htm";
  else if (asset == "/settings/sync") asset = "/settings_sync.htm";
  else if (asset == "/settings/time") asset = "/settings_time.htm";
  else if (asset == "/settings/um") asset = "/settings_um.htm";
  else if (asset == "/settings/sec") asset = "/settings_sec.htm";
  else if (asset == "/welcome") asset = "/welcome.htm";
  else if (asset == "/edit") asset = "/edit.htm";
  else if (asset == "/liveview") asset = "/liveview.htm";
  else if (asset == "/liveview2D") asset = "/liveviewws2D.htm";
  else if (asset == "/style.css") asset = "/style.css";

  if (asset.find("..") != std::string::npos) return {};
  if (!asset.empty() && asset[0] == '/') asset.erase(0, 1);
  return webRoot / asset;
}

std::string readFile(const std::filesystem::path &path) {
  std::ifstream file(path, std::ios::binary);
  if (!file) return "";
  std::ostringstream contents;
  contents << file.rdbuf();
  return contents.str();
}

