NativeHttpServer::NativeHttpServer(const NativeHttpServerOptions &options) : _options(options), _fallbackRenderBuffer(30) {
  _fallbackCore.begin(_fallbackRenderBuffer.length(), millis());
}

NativeHttpServer::~NativeHttpServer() {
  stop();
}

NativeHttpServer::NativeHttpServer(NativeHttpServer &&other) noexcept {
  *this = std::move(other);
}

NativeHttpServer &NativeHttpServer::operator=(NativeHttpServer &&other) noexcept {
  if (this == &other) return *this;
  stop();
  _options = std::move(other._options);
  _fallbackRenderBuffer = std::move(other._fallbackRenderBuffer);
  _state = other._state;
  _running.store(other._running.load());
  _listenFd = other._listenFd;
  _localPort = other._localPort;
  _startMs = other._startMs;
  _fallbackCore.begin(_fallbackRenderBuffer.length(), millis());
  if (other._acceptThread.joinable()) _acceptThread = std::move(other._acceptThread);
  other._listenFd = -1;
  other._running.store(false);
  return *this;
}

bool NativeHttpServer::start() {
  if (_running.load()) return true;

  _listenFd = socket(AF_INET, SOCK_STREAM, 0);
  if (_listenFd < 0) return false;

  const int reuse = 1;
  setsockopt(_listenFd, SOL_SOCKET, SO_REUSEADDR, &reuse, sizeof(reuse));

  sockaddr_in address{};
  address.sin_family = AF_INET;
  address.sin_port = htons(_options.port);
  if (_options.host == "localhost") _options.host = "127.0.0.1";
  if (inet_pton(AF_INET, _options.host.c_str(), &address.sin_addr) != 1) {
    close(_listenFd);
    _listenFd = -1;
    return false;
  }

  if (bind(_listenFd, reinterpret_cast<sockaddr *>(&address), sizeof(address)) != 0) {
    close(_listenFd);
    _listenFd = -1;
    return false;
  }

  if (listen(_listenFd, 16) != 0) {
    close(_listenFd);
    _listenFd = -1;
    return false;
  }

  socklen_t length = sizeof(address);
  if (getsockname(_listenFd, reinterpret_cast<sockaddr *>(&address), &length) == 0) _localPort = ntohs(address.sin_port);
  else _localPort = _options.port;

  _startMs = millis();
  _running.store(true);
  _acceptThread = std::thread(&NativeHttpServer::acceptLoop, this);
  return true;
}

void NativeHttpServer::stop() {
  if (!_running.exchange(false) && _listenFd < 0) return;
  if (_listenFd >= 0) {
    shutdown(_listenFd, SHUT_RDWR);
    close(_listenFd);
    _listenFd = -1;
  }
  if (_acceptThread.joinable()) _acceptThread.join();
}

bool NativeHttpServer::running() const {
  return _running.load();
}

uint16_t NativeHttpServer::localPort() const {
  return _localPort;
}

const NativeLightState &NativeHttpServer::state() const {
  return _state;
}

void NativeHttpServer::acceptLoop() {
  while (_running.load()) {
    sockaddr_in remote{};
    socklen_t remoteLength = sizeof(remote);
    const int client = accept(_listenFd, reinterpret_cast<sockaddr *>(&remote), &remoteLength);
    if (client < 0) {
      if (_running.load()) std::this_thread::sleep_for(std::chrono::milliseconds(1));
      continue;
    }
    configureClientSocket(client);
    std::thread(&NativeHttpServer::handleClient, this, client).detach();
  }
}

void NativeHttpServer::handleClient(int clientFd) {
  const std::string raw = readRequest(clientFd);
  HttpRequest request;
  if (!parseRequest(raw, request)) {
    sendHttp(clientFd, 400, "text/plain; charset=utf-8", "Bad Request\n");
    close(clientFd);
    return;
  }

  if (request.path == "/ws" && lower(request.headers["upgrade"]) == "websocket") {
    handleWebSocket(clientFd, raw);
    close(clientFd);
    return;
  }

  core().tick(millis());

  if (request.method == "GET" && request.path == "/json/effects") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", core().jsonEffects());
  } else if (request.method == "GET" && request.path == "/json/fxdata") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", core().jsonFxData());
  } else if (request.method == "GET" && request.path == "/json/palettes") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", core().jsonPalettes());
  } else if (request.method == "GET" && request.path == "/json/palx") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", core().jsonPaletteData());
  } else if (request.method == "GET" && request.path == "/settings/s.js") {
    sendHttp(clientFd, 200, "application/javascript; charset=utf-8", settingsCompatibilityJs());
  } else if (request.method == "GET" && (request.path == "/json" || request.path == "/json/si")) {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", jsonStateInfo());
  } else if (request.method == "GET" && request.path == "/json/state") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", jsonState());
  } else if (request.method == "GET" && request.path == "/json/info") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", jsonInfo());
  } else if (request.method == "GET" && request.path == "/presets.json") {
    sendHttp(clientFd, 200, "application/json; charset=utf-8", core().presetsJson());
  } else if (request.method == "POST" && (request.path == "/json" || request.path == "/json/state")) {
    applyJsonState(request.body);
    sendHttp(clientFd, 200, "application/json; charset=utf-8", "{\"success\":true}");
  } else if (request.method == "GET" && request.path == "/version") {
    sendHttp(clientFd, 200, "text/plain; charset=utf-8", _options.version);
  } else if (request.method == "GET" && request.path == "/uptime") {
    sendHttp(clientFd, 200, "text/plain; charset=utf-8", std::to_string(millis() - _startMs));
  } else if (request.method == "GET" && request.path == "/freeheap") {
    sendHttp(clientFd, 200, "text/plain; charset=utf-8", std::to_string(getFreeHeap()));
  } else if (request.path == "/update") {
    sendHttp(clientFd, 410, "text/plain; charset=utf-8", "Native WLED does not support firmware OTA updates.\n");
  } else if (request.path == "/upload") {
    sendHttp(clientFd, 501, "text/plain; charset=utf-8", "Native WLED upload endpoints are not implemented yet.\n");
  } else if (request.method == "GET") {
    const std::filesystem::path asset = routeToAsset(_options.webRoot, request.path);
    if (!asset.empty() && std::filesystem::is_regular_file(asset)) {
      sendHttp(clientFd, 200, contentTypeFor(asset), readFile(asset));
    } else {
      sendHttp(clientFd, 404, "text/plain; charset=utf-8", "Not Found\n");
    }
  } else {
    sendHttp(clientFd, 405, "text/plain; charset=utf-8", "Method Not Allowed\n");
  }
  close(clientFd);
}

void NativeHttpServer::handleWebSocket(int clientFd, const std::string &rawRequest) {
  HttpRequest request;
  if (!parseRequest(rawRequest, request)) return;
  const auto key = request.headers.find("sec-websocket-key");
  if (key == request.headers.end()) return;

  std::ostringstream response;
  response << "HTTP/1.1 101 Switching Protocols\r\n"
           << "Upgrade: websocket\r\n"
           << "Connection: Upgrade\r\n"
           << "Sec-WebSocket-Accept: " << websocketAccept(key->second) << "\r\n\r\n";
  if (!sendAll(clientFd, response.str())) return;
  if (!sendWebSocketText(clientFd, jsonStateInfo())) return;

  while (_running.load()) {
    uint8_t opcode = 0;
    std::string payload;
    if (!readWebSocketFrame(clientFd, opcode, payload)) break;
    if (opcode == 0x08) break;
    if (opcode != 0x01) continue;

    if (payload == "p") {
      if (!sendWebSocketText(clientFd, "pong")) break;
    } else if (payload.find("\"lv\"") != std::string::npos) {
      if (!sendWebSocketBinary(clientFd, liveViewPayload(renderBuffer()))) break;
    } else {
      applyJsonState(payload);
      if (payload.find("\"v\"") != std::string::npos) {
        if (!sendWebSocketText(clientFd, jsonStateInfo())) break;
      } else if (!sendWebSocketText(clientFd, "{\"success\":true}")) {
        break;
      }
    }
  }
}

std::string NativeHttpServer::jsonState() const {
  return core().jsonState(millis());
}

std::string NativeHttpServer::jsonInfo() const {
  return core().jsonInfo(_options.version, _options.nativeMac, renderBuffer(), millis());
}

std::string NativeHttpServer::jsonStateInfo() const {
  return core().jsonStateInfo(_options.version, _options.nativeMac, renderBuffer(), millis());
}

void NativeHttpServer::applyJsonState(const std::string &body) {
  core().applyJsonState(body, millis());
}

NativeRenderBuffer &NativeHttpServer::renderBuffer() {
  return _options.renderBuffer ? *_options.renderBuffer : _fallbackRenderBuffer;
}

const NativeRenderBuffer &NativeHttpServer::renderBuffer() const {
  return _options.renderBuffer ? *_options.renderBuffer : _fallbackRenderBuffer;
}

NativeWledCore &NativeHttpServer::core() {
  return _options.core ? *_options.core : _fallbackCore;
}

const NativeWledCore &NativeHttpServer::core() const {
  return _options.core ? *_options.core : _fallbackCore;
}
